            <path d="M1126 972L1131 909.5L1238.5 915L1240.5 939L1258 972L1255 996L1186 1008.5L1131 1023.5L1126 972Z" class="hitbox" role="button" tabindex="0" aria-label="submit RSVP" onclick={() => {
