<style>
    @import url('https://fonts.googleapis.com/css2?family=EB+Garamond:ital,wght@0,400..800;1,400..800&display=swap');

    :global(:root) {
        --dark-brown: #332421;
        --cream: #f7eee3;
    }

    :global(body) {
        margin: 0;
        color: var(--dark-brown);
        background-color: var(--cream);
        font-family: "EB Garamond", serif;
    }

    .parallax-wrapper {
        perspective: 10px;
        perspective-origin: center center;
        height: 100vh;
        overflow-x: hidden;
        overflow-y: auto;
    }

    .hero {
        position: relative;
        display: flex;
        width: 100%;
        min-height: calc(100vw*9/16 + 20vh);
        /* min-height: 100vh; */
        flex-direction: column;
        justify-content: center;
        align-items: center;
        transform-style: preserve-3d;
        will-change: transform;
    }

    .hero-logo {
        width: 60%;
        position: relative;
        /* transform: translateZ(-5px) scale(1.5); */
    }

    .hero-tagline {
        font-size: 2.5vw;
        margin: 0;
        font-style: italic;
    }

    .hero-frame {
        width: 100%;
        position: absolute;
        transform: translateZ(1px) scale(0.9);
        pointer-events: none;
    }

    .hero-gargoyle {
        position: absolute;
        width: 15%;
        z-index: 20;
    }

    .gargoyle-left {
        animation: rotate1 2s ease-in-out infinite alternate;
        left: 10%;
    }

    @keyframes rotate1 {
        from { transform: rotate(15deg) translateY(-20vh) translateZ(2px) scale(0.8); }
        to { transform: rotate(0deg) translateY(-20vh) translateZ(2px) scale(0.8); }
    }

    .gargoyle-right {
        animation: rotate2 2s ease-in-out infinite alternate;
        right: 10%;
        transform: translateY(-30vh);
    }

    @keyframes rotate2 {
        from { transform: rotate(15deg) translateY(20vh) translateZ(2px) scale(0.8); }
        to { transform: rotate(0deg) translateY(20vh) translateZ(2px) scale(0.8); }
    }
    
    .rsvp-container {
        position: absolute !important;
        transform: translateY(-5vh) translateZ(1px) scale(0.7);
        z-index: 30;
        width: min(100vw, 177.78vh);
        height: min(56.25vw, 100vh);
        pointer-events: auto;
        display: flex;
        justify-content: center;
        align-items: center;
    }

    .rsvp-layer {
        position: absolute;
        top: 0;
        left: 0;
        width: 100%;
        height: auto;
        object-fit: contain;
        pointer-events: none;
        transition: transform 0.3s ease, filter 0.3s ease;
    }

    .rsvp-layer.submitted {
        transform: translateY(-10rem);
        opacity: 0;
        pointer-events: none;
        transition: transform 0.6s ease, opacity 0.6s ease;
    }

    .rsvp-layer.submitted2 {
        transform: translateY(12rem);
        opacity: 0;
        pointer-events: none;
        transition: transform 1s ease, opacity 1s ease;
    }

    .rsvp-layer:hovered {
        transform: translate(-5px, -5px);
        filter: brightness(1.3) drop-shadow(5px 5px 0 rgba(0, 0, 0, 0.3));
    }

    .rsvp-svg {
        z-index: 100;
        pointer-events: none;
    }

    .hitbox {
        pointer-events: auto !important;
        cursor: pointer;
        fill: white;
        opacity: 0;
    }

    .rsvp-form {
        position: absolute;
        width: calc(400/1920*100%);
        height: calc(100/1080*100%);
        left: calc(725/1920*100%);
        top: calc(915/1080*100%);
        z-index: 100;
    }

    .rsvp-form input {
        width: 100%;
        height: 100%;
        background: transparent;
        border: none;
        font-size: 2.0vw;
        font-style: italic;
        font-family: "EB Garamond", serif;
    }

    .rsvp-button {
        position: absolute;
        pointer-events: auto;
        cursor: pointer;
    }
    
    .rsvp-container:not(.submitted):has(.hitbox:hover) .rsvp-button {
        filter: brightness(0.9);
    }

    .rsvp-container:not(.submitted):has(.hitbox:active) .rsvp-button {
        filter: brightness(0.7);
    }

    .rsvp-button.submitting {
        filter: grayscale(0.5);
        pointer-events: none;
    }

    .form-message {
        position: absolute;
        left: 50%;
        transform: translateX(-50%);
        top: calc(915/1080*100%);
        z-index: 10;
        font-size: 1.8vw !important;
        color: color-mix(in srgb, var(--dark-brown), transparent 30%);
        font-style: italic;
    }
    
    .form-message.error {
        bottom: calc(915/1080*100%) !important;
    }
</style>